import java.util.Scanner;

public class SecureBuffer {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Validate input length
        if (userInput.length() > 10) {
            System.out.println("Input exceeds maximum allowed length.");
            return;
        }

        // Dynamically allocate memory for buffer based on user input length
        char[] buffer = new char[userInput.length()];

        // Copy user input into the dynamically allocated buffer
        userInput.getChars(0, userInput.length(), buffer, 0);

        System.out.println("User input copied to buffer successfully.");
    }
}

### Explanation:
취약유형: Buffer Overflow
